#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


float z = q30;
float d = q31;
float pi = q28;
float pi2inv = q29;
float mask_apex = q32;
float zoom = q27;

vec2 c = zoom*(vUv-0.5)*uAspect.xy;

float camera_apex = atan( length(c),z);

bool mask = mask_apex >= camera_apex;

float longitude = atan(c.x,c.y);
float latitude = (pi - camera_apex + asin(d*sin(camera_apex)));

vec2 polar = vec2(longitude,latitude);

vec3 p = vec3( sin(polar.x)*sin(polar.y),cos(polar.x)*sin(polar.y),cos(polar.y));

factorA = p.zy;
factorB = vec2(q20,q21);
product = cmul(factorA,factorB);
p.zy = product.xy;

factorA = p.zx;
factorB = vec2(q22,q23);
product = cmul(factorA,factorB);
p.zx = product.xy;

//clouds
vec3 cp = p;
factorA = cp.zx;
factorB = vec2(q11,q12);
product = cmul(factorA,factorB);
cp.zx = product.xy;

factorA = p.yx;
factorB = vec2(q24,q25);
product = cmul(factorA,factorB);
p.yx = product.xy;

vec2 cpolar = polar;
vec2 cpolars = polar;
polar = vec2(atan(p.z,p.x),atan(p.y,length(p.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);
cpolar = vec2(atan(cp.z,cp.x),atan(cp.y,length(cp.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);
cp = cp+0.015;
cpolars = vec2(atan(cp.z,cp.x),atan(cp.y,length(cp.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);

//--------
polar = -polar;
//vec2 uv4 = (multiply(vUv,mat2(.6,.8,-.8,.6)));
vec2 uv4 = 64*vec2(vUv.x+q10*0.15, vUv.y);
vec3 smask = (texture(sampler_pw_noise_lq,uv4/256)).g-.9;
float stars = clamp01(.5/length(abs(fract(uv4)-.5))*smask);
uv4 = vec2(uv4.y+5, uv4.x+4)*3;
smask = (texture(sampler_pw_noise_lq,uv4/256)).g-.9;
stars +=  clamp01(.5/length(abs(fract(uv4)-.5))*smask);
stars *= 1-mask;
stars *= stars;

vec3 night = texture(sampler_pano_earth_night, polar);
vec3 light = vec3(0.5,-q14,-q13);
vec3 lightdir = normalize(light);
float diffuse = clamp01(dot(lightdir, normalize(p*mask)));
vec3 nor = normalize(normalize(lightdir) + normalize(p));
float spec = pow(clamp01(dot(normalize(p*mask),nor)),50);
vec3 specCol = texture(sampler_pano_earth_spec, polar)*(spec*diffuse);
specCol *= vec3(0.7,0.7,0.8);

night = night * clamp01(1-diffuse) * mask;

//--------
ret = mask*tex2d(sampler_pano_earth,polar);
vec3 clouds = mask*tex2d(sampler_pano_earth_clouds,cpolar);
vec3 cshadow = mask*tex2d(sampler_pano_earth_clouds,cpolars);
specCol *= 1-clouds;
//specCol *= cshadow;
ret = mix(ret,0,cshadow);
ret = mix(ret,1,clouds);
ret += specCol;
ret *= ret+0.3;
ret *= vec3(1,1,1.1);
ret = ret*diffuse+night;
ret += stars;

  fragColor = ret;
}

